const cfData = $('Fetch Codeforces').first().json.result || [];
const lcData = $('Fetch LeetCode').first().json.data.topTwoContests || [];

const now = Math.floor(Date.now() / 1000);
const d = new Date();
const currentDay = d.getDay(); // 0 (Sun) to 6 (Sat)
const currentHour = d.getHours(); // 0 to 23

let message = "";
let send = false;

// Format helper
function getTimeRemaining(startTime) {
  const diff = startTime - now;
  const days = Math.floor(diff / (24 * 60 * 60));
  const hours = Math.floor((diff % (24 * 60 * 60)) / (60 * 60));
  if (days === 0 && hours === 0) return "in less than an hour!";
  if (days === 0) return `in ${hours} hour${hours > 1 ? "s" : ""}`;
  if (hours === 0) return `in ${days} day${days > 1 ? "s" : ""}`;
  return `in ${days} day${days > 1 ? "s" : ""} and ${hours} hour${hours > 1 ? "s" : ""}`;
}

// Find next contests
const cfUpcoming = cfData.filter(c => c.phase === "BEFORE" && c.startTimeSeconds >= now);
cfUpcoming.sort((a, b) => a.startTimeSeconds - b.startTimeSeconds);
const nextCf = cfUpcoming.length > 0 ? cfUpcoming[0] : null;

const lcUpcoming = lcData.filter(c => c.startTime >= now);
lcUpcoming.sort((a, b) => a.startTime - b.startTime);
const nextLc = lcUpcoming.length > 0 ? lcUpcoming[0] : null;

// 1. Check for 1 HOUR REMINDER (Starts in >0 and <=75 mins to be safe if running hourly)
let oneHourAlerts = [];
if (nextCf && (nextCf.startTimeSeconds - now) <= 75 * 60 && (nextCf.startTimeSeconds - now) > 0) {
  oneHourAlerts.push(`*Codeforces:* ${nextCf.name}`);
}
if (nextLc && (nextLc.startTime - now) <= 75 * 60 && (nextLc.startTime - now) > 0) {
  oneHourAlerts.push(`*LeetCode:* ${nextLc.title}`);
}

// 2. Check for MORNING OF CONTEST (Starts today, and it is 9 AM)
let morningAlerts = [];
if (currentHour === 9) {
  if (nextCf && (nextCf.startTimeSeconds - now) <= 24 * 3600) {
      morningAlerts.push(`*Codeforces:* ${nextCf.name} (Starts ${getTimeRemaining(nextCf.startTimeSeconds)})`);
  }
  if (nextLc && (nextLc.startTime - now) <= 24 * 3600) {
      morningAlerts.push(`*LeetCode:* ${nextLc.title} (Starts ${getTimeRemaining(nextLc.startTime)})`);
  }
}

// Evaluate Conditions
if (oneHourAlerts.length > 0) {
  message = "🔥 *CONTEST STARTING IN 1 HOUR!* 🔥\n\n" + oneHourAlerts.join("\n");
  send = true;
} 
else if (morningAlerts.length > 0) {
  message = "🌅 *Contest Today!* Good morning, get ready:\n\n" + morningAlerts.join("\n");
  send = true;
} 
else if (currentHour === 9 && (currentDay === 1 || currentDay === 4)) {
  // Monday(1) or Thursday(4) at 9 AM: Weekly Overview
  message = "*📅 Weekly Contest Overview*\n\n";
  if (nextCf) message += `*Codeforces:* ${nextCf.name} is ${getTimeRemaining(nextCf.startTimeSeconds)}\n`;
  if (nextLc) message += `*LeetCode:* ${nextLc.title} is ${getTimeRemaining(nextLc.startTime)}\n`;
  send = true;
}

if (!send) {
  return []; // Stop workflow, do not send anything
}

return { message };
